import { NavLink, Outlet, useNavigate } from "react-router-dom";
import { clearSession, getStoredSession } from "../services/auth";

export default function AppShell() {
  const navigate = useNavigate();
  const session = getStoredSession();
  const isAdmin = session?.role === "admin";
  const todayLabel = new Intl.DateTimeFormat("en-US", {
    dateStyle: "full"
  }).format(new Date());
  const navItems = isAdmin
    ? [{ to: "/admin/gym-owners", label: "Gym Owners" }]
    : [
        { to: "/dashboard", label: "Dashboard" },
        { to: "/customers", label: "Customers" },
        { to: "/payments", label: "Payments" },
        { to: "/add", label: "Add Customer" },
        { to: "/attendance", label: "Attendance" }
      ];

  const handleLogout = () => {
    clearSession();
    navigate("/login");
  };

  return (
    <div className="app-shell">
      <aside className="app-shell__sidebar">
        <div className="app-shell__sidebar-top">
          <div className="brand-mark">fitLedger</div>
          <nav className="app-shell__nav" aria-label="Primary">
            {navItems.map((item) => (
              <NavLink
                key={item.to}
                to={item.to}
                className={({ isActive }) =>
                  `app-shell__nav-link${isActive ? " is-active" : ""}`
                }
              >
                {item.label}
              </NavLink>
            ))}
          </nav>
        </div>

        <div className="app-shell__sidebar-note">
          <span className="sidebar-note__label">{isAdmin ? "Admin mode" : "Today"}</span>
          <strong>{isAdmin ? session?.name || "Product Admin" : todayLabel}</strong>
          <span>
            {isAdmin
              ? "Manage gym owner records and watch account health."
              : "Track check-ins and renewals."}
          </span>
        </div>
      </aside>

      <div className="app-shell__main">
        <header className="app-shell__header">
          <div>
            <span className="eyebrow">
              {isAdmin ? "Product admin console" : "Front desk console"}
            </span>
            <p className="app-shell__header-copy">
              {isAdmin
                ? "Monitor gym owners, maintain records, and track their member counts."
                : "Manage members, attendance, and renewals from the live database."}
            </p>
          </div>

          <button className="button button--ghost" onClick={handleLogout}>
            Log out
          </button>
        </header>

        <main className="app-shell__content">
          <Outlet />
        </main>
      </div>
    </div>
  );
}
